CREATE TABLE `physquiz` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `question` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `option_1` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `option_2` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `option_3` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `option_4` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `answer` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `explanation` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `user_id` bigint unsigned NOT NULL,
  `category_id` bigint unsigned NOT NULL,
  `urlCode` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `option_5` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `content_type` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `physquiz_user_id_foreign` (`user_id`),
